<template><AppLayout><main class="community-page"><header class="community-head"><div><h1>共享与商城</h1><p>审核提现、处理工单、配置抽成并管理数字商品库存。</p></div></header><nav class="community-tabs"><button v-for="t in tabs" :key="t.key" :class="{active:tab===t.key}" @click="tab=t.key">{{t.label}}</button></nav>
<section v-if="tab==='settings'" class="community-form"><h2>账号广场结算</h2><label>平台抽成比例（%）<input v-model.number="commission" class="community-input" type="number" min="0" max="100" step="0.01"></label><p>新发布的共享方案会快照当前比例；已发布方案不会随配置变化。</p><button class="community-btn" @click="saveCommission">保存配置</button></section>
<div v-if="tab==='accounts'" class="community-table-wrap"><table class="community-table"><thead><tr><th>用户账号</th><th>平台 / 等级</th><th>共享</th><th>并发</th><th>审核状态</th><th>提交时间</th><th>操作</th></tr></thead><tbody><tr v-if="accounts.length===0"><td colspan="7"><div class="community-empty compact">暂无待审核账号</div></td></tr><tr v-for="account in accounts" v-else :key="account.id"><td><strong>{{account.name}}</strong><small>#{{account.id}} · 用户 {{account.owner_user_id}}</small></td><td><span class="community-provider" :data-provider="account.provider">{{account.provider}}</span><small>{{account.account_tier||'OAuth'}}</small></td><td>{{account.share_mode==='public'?'公共':'私有'}}</td><td>{{account.concurrency}}</td><td><span class="community-status" :class="`community-status--${account.review_status||account.status}`">{{account.review_status||account.status}}</span><small v-if="account.review_note">{{account.review_note}}</small></td><td>{{format(account.created_at)}}</td><td><div class="community-toolbar"><button v-if="account.review_status==='pending'||account.status==='pending'" class="community-btn" @click="reviewAccount(account,'approved')">批准并激活</button><button v-if="account.review_status==='pending'||account.status==='pending'" class="community-btn community-btn--danger" @click="reviewAccount(account,'rejected')">拒绝</button></div></td></tr></tbody></table></div>
<div v-if="tab==='withdrawals'" class="community-table-wrap"><table class="community-table"><thead><tr><th>用户</th><th>金额/手续费</th><th>方式</th><th>状态</th><th>提交时间</th><th>操作</th></tr></thead><tbody><tr v-for="w in withdrawals" :key="w.id"><td>{{w.user_email}}</td><td>¥{{w.amount.toFixed(2)}} / ¥{{w.fee.toFixed(2)}}</td><td>{{w.payout_method}}</td><td>{{w.status}}</td><td>{{format(w.created_at)}}</td><td><div class="community-toolbar"><button v-if="w.status==='pending'" class="community-btn" @click="review(w,'approved')">通过</button><button v-if="w.status==='pending'" class="community-btn community-btn--danger" @click="review(w,'rejected')">驳回</button><button v-if="w.status==='approved'" class="community-btn" @click="review(w,'paid')">确认已打款</button><a :href="w.payout_snapshot" target="_blank" class="community-btn community-btn--quiet">收款码</a></div></td></tr></tbody></table></div>
<section v-if="tab==='tickets'" class="community-split"><aside class="community-list"><button v-for="t in tickets" :key="t.id" :class="{active:ticket?.id===t.id}" @click="openTicket(t.id)"><strong>{{t.subject}}</strong><small>#{{t.id}} · {{t.status}} · 未读 {{t.admin_unread}}</small></button></aside><article v-if="ticket" class="community-form"><div class="community-row"><h2>{{ticket.subject}}</h2><select v-model="ticket.status" class="community-select" @change="setTicketStatus"><option value="open">处理中</option><option value="waiting_user">等待用户</option><option value="resolved">已解决</option><option value="closed">已关闭</option></select></div><div class="community-messages"><div v-for="m in ticket.messages" :key="m.id" class="community-message" :class="m.author_role"><small>{{m.author_role}}</small><p>{{m.content}}</p></div></div><form class="community-toolbar" @submit.prevent="replyTicket"><input v-model="reply" class="community-input" style="flex:1" required><button class="community-btn">回复</button></form></article></section>
<section v-if="tab==='products'" class="community-page"><form class="community-form" @submit.prevent="saveProduct"><div class="community-form-grid"><label>商品名<input v-model="product.name" class="community-input" required></label><label>分类<input v-model="product.category" class="community-input"></label><label>余额价格<input v-model.number="product.price" type="number" step="0.01" min="0" class="community-input"></label><label>积分价格（留空不支持）<input v-model.number="product.points_price" type="number" step="0.01" min="0" class="community-input"></label><label>交付类型<select v-model="product.fulfillment_type" class="community-select"><option value="card">卡密</option><option value="redeem_code">兑换码</option><option value="balance">余额到账</option><option value="entitlement">负载额度（增加用户并发）</option></select></label><label>交付数值<input v-model.number="product.fulfillment_value" type="number" :step="product.fulfillment_type==='entitlement'?1:0.01" min="0" class="community-input"></label><label>状态<select v-model="product.status" class="community-select"><option value="draft">草稿</option><option value="active">上架</option><option value="inactive">下架</option></select></label></div><label>描述<textarea v-model="product.description" class="community-textarea"></textarea></label><button class="community-btn">保存商品</button></form><div class="community-table-wrap"><table class="community-table"><thead><tr><th>商品</th><th>余额价</th><th>积分价</th><th>库存</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-for="p in products" :key="p.id"><td>{{p.name}}</td><td>¥{{p.price.toFixed(2)}}</td><td>{{p.points_price==null?'-':p.points_price}}</td><td>{{['card','redeem_code'].includes(p.fulfillment_type)?p.stock:'无需库存'}}</td><td>{{p.status}}</td><td><button class="community-btn community-btn--quiet" @click="editProduct(p)">编辑</button><button v-if="['card','redeem_code'].includes(p.fulfillment_type)" class="community-btn" @click="stock(p)">入库</button></td></tr></tbody></table></div></section>
<div v-if="tab==='orders'" class="community-table-wrap"><table class="community-table"><thead><tr><th>订单号</th><th>用户</th><th>商品</th><th>数量</th><th>支付方式</th><th>金额</th><th>状态</th><th>交付内容</th><th>创建时间</th></tr></thead><tbody><tr v-if="storeOrders.length===0"><td colspan="9"><div class="community-empty compact">暂无商城订单</div></td></tr><tr v-for="order in storeOrders" v-else :key="order.id"><td>{{order.order_no}}</td><td>#{{order.user_id}}</td><td>{{order.product_name}}</td><td>{{order.quantity}}</td><td>{{order.payment_source==='points'?'积分':order.payment_source==='platform'?'平台支付':'余额'}}</td><td>{{order.payment_source==='points'?'':'¥'}}{{order.total_amount.toFixed(2)}}</td><td>{{order.status}}</td><td><code>{{Array.isArray(order.delivery)?order.delivery.join(' · '):order.delivery}}</code></td><td>{{format(order.created_at)}}</td></tr></tbody></table></div></main></AppLayout></template>
<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import AppLayout from '@/components/layout/AppLayout.vue';import{communityAPI,type CommunityAccount,type StoreOrder,type StoreProduct,type SupportTicket,type Withdrawal}from'@/api/community';import{useAppStore}from'@/stores/app';const app=useAppStore(),tab=ref('accounts'),commission=ref(10),accounts=ref<CommunityAccount[]>([]),withdrawals=ref<Withdrawal[]>([]),tickets=ref<SupportTicket[]>([]),ticket=ref<SupportTicket|null>(null),reply=ref(''),products=ref<StoreProduct[]>([]),storeOrders=ref<StoreOrder[]>([]);const tabs=[{key:'accounts',label:'账号审核'},{key:'withdrawals',label:'提现审核'},{key:'tickets',label:'工单'},{key:'products',label:'发卡商品'},{key:'orders',label:'商城订单'},{key:'settings',label:'抽成设置'}];const product=reactive<Partial<StoreProduct>>({category:'兑换码',name:'',description:'',price:0,points_price:null,fulfillment_type:'card',fulfillment_value:0,status:'draft',sort_order:0});const format=(v:string)=>new Date(v).toLocaleString('zh-CN');async function load(){try{const[s,a,w,t,p,o]=await Promise.all([communityAPI.admin.settings(),communityAPI.admin.accounts(),communityAPI.admin.withdrawals(),communityAPI.admin.tickets(),communityAPI.admin.products(),communityAPI.admin.orders()]);commission.value=s.commission_percent;accounts.value=a;withdrawals.value=w;tickets.value=t;products.value=p;storeOrders.value=o}catch{app.showError('管理数据加载失败')}}async function reviewAccount(account:CommunityAccount,decision:'approved'|'rejected'){const note=prompt(decision==='approved'?'审核备注（可选）':'请输入拒绝原因')||'';if(decision==='rejected'&&!note)return;try{await communityAPI.admin.reviewAccount(account.id,decision,note);await load();app.showSuccess(decision==='approved'?'账号已批准并进入独立调度':'账号已拒绝')}catch{app.showError('账号审核失败')}}async function saveCommission(){try{await communityAPI.admin.saveSettings(commission.value);app.showSuccess('抽成比例已保存')}catch{app.showError('保存失败')}}async function review(w:Withdrawal,status:string){const note=prompt('审核备注（可选）')||'';const payment_reference=status==='paid'?(prompt('请输入线下打款流水号')||''):'';if(status==='paid'&&!payment_reference){app.showError('确认已打款必须填写流水号');return}try{await communityAPI.admin.reviewWithdrawal(w.id,{status,note,payment_reference});await load();app.showSuccess(status==='paid'?'已记录线下打款':'提现状态已更新')}catch{app.showError('审核操作失败')}}async function openTicket(id:number){ticket.value=await communityAPI.admin.ticket(id)}async function setTicketStatus(){if(!ticket.value)return;await communityAPI.admin.ticketStatus(ticket.value.id,ticket.value.status);await load()}async function replyTicket(){if(!ticket.value)return;await communityAPI.admin.reply(ticket.value.id,reply.value);reply.value='';await openTicket(ticket.value.id);await load()}function editProduct(p:StoreProduct){Object.assign(product,p);tab.value='products'}async function saveProduct(){try{await communityAPI.admin.saveProduct(product);Object.assign(product,{id:undefined,category:'兑换码',name:'',description:'',price:0,points_price:null,fulfillment_type:'card',fulfillment_value:0,status:'draft',sort_order:0});await load();app.showSuccess('商品已保存')}catch{app.showError('商品保存失败')}}async function stock(p:StoreProduct){const raw=prompt('每行一个卡密或兑换码');if(!raw)return;try{await communityAPI.admin.addInventory(p.id,raw.split('\n').map(v=>v.trim()).filter(Boolean));await load();app.showSuccess('库存已入库')}catch{app.showError('入库失败')}}onMounted(load);</script><style src="@/styles/community.css"></style>
